 79→    private void updatePostsInFeed(long feedId, final UpdateAction action) {
 80→        ReaderActions.UpdateResultListener listener = new ReaderActions.UpdateResultListener() {
 81→            @Override
 82→            public void onUpdateResult(ReaderActions.UpdateResult result) {
 83→                EventBus.getDefault().post(new ReaderEvents.UpdatePostsEnded(result, action));
 84→                mCompletionListener.onCompleted(mListenerCompanion);
 85→            }
 86→        };
 87→        requestPostsForFeed(feedId, action, listener);
