209→    /*
210→     * called after requesting posts with a specific tag or in a specific blog/feed
211→     */
212→    private static void handleUpdatePostsResponse(final ReaderTag tag,
213→                                                  final JSONObject jsonObject,
214→                                                  final UpdateAction updateAction,
215→                                                  final ReaderActions.UpdateResultListener resultListener) {
216→        if (jsonObject == null) {
217→            resultListener.onUpdateResult(ReaderActions.UpdateResult.FAILED);
218→            return;
219→        }
220→
221→        new Thread() {
222→            @Override
223→            public void run() {
224→                ReaderPostList serverPosts = ReaderPostList.fromJson(jsonObject);
225→                ReaderActions.UpdateResult updateResult = ReaderPostTable.comparePosts(serverPosts);
226→                if (updateResult.isNewOrChanged()) {
227→                    // gap detection - only applies to posts with a specific tag
228→                    ReaderPost postWithGap = null;
229→                    if (tag != null) {
230→                        switch (updateAction) {
231→                            case REQUEST_NEWER:
232→                                // if there's no overlap between server and local (ie: all server
233→                                // posts are new), assume there's a gap between server and local
234→                                // provided that local posts exist
235→                                int numServerPosts = serverPosts.size();
236→                                if (numServerPosts >= 2
237→                                    && ReaderPostTable.getNumPostsWithTag(tag) > 0
238→                                    && !ReaderPostTable.hasOverlap(serverPosts, tag)) {
239→                                    // treat the second to last server post as having a gap
240→                                    postWithGap = serverPosts.get(numServerPosts - 2);
241→                                    // remove the last server post to deal with the edge case of
242→                                    // there actually not being a gap between local & server
243→                                    serverPosts.remove(numServerPosts - 1);
244→                                    ReaderBlogIdPostId gapMarker = ReaderPostTable.getGapMarkerIdsForTag(tag);
245→                                    if (gapMarker != null) {
246→                                        // We mustn't have two gapMarkers at the same time. Therefor we need to
247→                                        // delete all posts before the current gapMarker and clear the gapMarker flag.
248→                                        ReaderPostTable.deletePostsBeforeGapMarkerForTag(tag);
249→                                        ReaderPostTable.removeGapMarkerForTag(tag);
250→                                    }
251→                                }
252→                                break;
253→                            case REQUEST_OLDER_THAN_GAP:
254→                                // if service was started as a request to fill a gap, delete existing posts
255→                                // before the one with the gap marker, then remove the existing gap marker
256→                                ReaderPostTable.deletePostsBeforeGapMarkerForTag(tag);
257→                                ReaderPostTable.removeGapMarkerForTag(tag);
258→                                break;
259→                            case REQUEST_REFRESH:
260→                                ReaderPostTable.deletePostsWithTag(tag);
261→                                break;
262→                            case REQUEST_OLDER:
263→                                // no-op
264→                                break;
265→                        }
266→                    }
267→                    ReaderPostTable.addOrUpdatePosts(tag, serverPosts);
268→                    if (AppPrefs.shouldUpdateBookmarkPostsPseudoIds(tag)) {
269→                        ReaderPostTable.updateBookmarkedPostPseudoId(serverPosts);
270→                        AppPrefs.setBookmarkPostsPseudoIdsUpdated();
271→                    }
272→
273→                    // gap marker must be set after saving server posts
274→                    if (postWithGap != null) {
275→                        ReaderPostTable.setGapMarkerForTag(postWithGap.blogId, postWithGap.postId, tag);
276→                        AppLog.d(AppLog.T.READER, "added gap marker to tag " + tag.getTagNameForLog());
277→                    }
278→                } else if (updateResult == ReaderActions.UpdateResult.UNCHANGED
279→                           && updateAction == UpdateAction.REQUEST_OLDER_THAN_GAP) {
280→                    // edge case - request to fill gap returned nothing new, so remove the gap marker
281→                    ReaderPostTable.removeGapMarkerForTag(tag);
282→                    AppLog.w(AppLog.T.READER, "attempt to fill gap returned nothing new");
283→                }
284→                AppLog.d(AppLog.T.READER, "requested posts response = " + updateResult.toString());
285→                resultListener.onUpdateResult(updateResult);
286→            }
287→        }.start();
288→    }
