290→    /*
291→     * returns the endpoint to use when requesting posts with the passed tag
292→     */
293→    private static String getRelativeEndpointForTag(ReaderTag tag) {
294→        if (tag == null) {
295→            return null;
296→        }
297→
298→        // if passed tag has an assigned endpoint, return it and be done
299→        if (!TextUtils.isEmpty(tag.getEndpoint())) {
300→            return getRelativeEndpoint(tag.getEndpoint());
301→        }
302→
303→        // check the db for the endpoint
304→        String endpoint = ReaderTagTable.getEndpointForTag(tag);
305→        if (!TextUtils.isEmpty(endpoint)) {
306→            return getRelativeEndpoint(endpoint);
307→        }
308→
309→        // never hand craft the endpoint for default tags, since these MUST be updated
310→        // using their stored endpoints
311→        if (tag.tagType == ReaderTagType.DEFAULT) {
312→            return null;
313→        }
314→        return formatRelativeEndpointForTag(tag.getTagSlug());
315→    }
